import type { Configuration } from '@azure/msal-browser';

/**
 * MSAL (Entra ID) PKCE configuration for the SPA.
 *
 * - redirectUri  : computed at runtime from window.location.origin (never a VITE_* var).
 * - cacheLocation: sessionStorage (tokens are NOT persisted across tab sessions).
 * - Auth flows   : acquireTokenPopup / loginPopup only — never redirect.
 *
 * VITE_MSAL_CLIENT_ID      → SPA's own app-registration client ID.
 * VITE_MSAL_API_CLIENT_ID  → API app-registration client ID used to build the access scope.
 */

/** Redirect URI is always derived from the current origin at runtime. */
const redirectUri = `${window.location.origin}/welcome`;

/** API scope constructed at runtime from the API's client ID. */
export const apiScope = `api://${import.meta.env.VITE_MSAL_API_CLIENT_ID}/access_as_user`;

export const msalConfig: Configuration = {
  auth: {
    clientId: import.meta.env.VITE_MSAL_CLIENT_ID ?? '',
    authority: 'https://login.microsoftonline.com/common',
    redirectUri,
  },
  cache: {
    cacheLocation: 'sessionStorage',
    storeAuthStateInCookie: false,
  },
};

/** Scopes used during interactive sign-in (popup). */
export const loginRequest = {
  scopes: [apiScope],
};
