import { useMsal, useIsAuthenticated } from '@azure/msal-react';
import { loginRequest } from '../authConfig';

/**
 * Minimal auth affordance wired to MSAL.
 * Uses popup flows only — never redirect (per auth-entra contract).
 */
function AuthStatus() {
  const { instance, accounts } = useMsal();
  const isAuthenticated = useIsAuthenticated();

  if (isAuthenticated) {
    const name = accounts[0]?.name ?? accounts[0]?.username ?? 'account';
    return (
      <section aria-label="auth status" className="auth">
        <span>Signed in as {name}</span>
        <button
          type="button"
          onClick={() => {
            void instance.logoutPopup();
          }}
        >
          Sign out
        </button>
      </section>
    );
  }

  return (
    <section aria-label="auth status" className="auth">
      <button
        type="button"
        onClick={() => {
          void instance.loginPopup(loginRequest);
        }}
      >
        Sign in
      </button>
    </section>
  );
}

export default AuthStatus;
