/** Shape of the /health API response. */
export interface HealthResponse {
  status: string;
}

/**
 * Fetches the WAF-relative /health endpoint.
 * The path is intentionally relative so it works through any WAF/proxy
 * without needing a VITE_* base-URL variable.
 */
export async function fetchHealth(): Promise<HealthResponse> {
  const res = await fetch('/health');
  if (!res.ok) {
    throw new Error(`Health check responded with ${res.status}`);
  }
  return res.json() as Promise<HealthResponse>;
}
