import { render, screen, waitFor } from '@testing-library/react';
import { describe, expect, it, vi, beforeEach } from 'vitest';
import HealthStatus from './HealthStatus';

/** Helper: resolve fetch with a JSON body. */
function mockFetchOk(body: unknown) {
  vi.stubGlobal(
    'fetch',
    vi.fn().mockResolvedValue({
      ok: true,
      json: () => Promise.resolve(body),
    } as unknown as Response),
  );
}

/** Helper: reject fetch entirely. */
function mockFetchFail() {
  vi.stubGlobal('fetch', vi.fn().mockRejectedValue(new Error('network error')));
}

describe('HealthStatus', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('shows a loading placeholder initially', () => {
    mockFetchOk({ status: 'healthy' });
    render(<HealthStatus />);
    expect(screen.getByRole('status')).toHaveTextContent('checking');
  });

  it('shows the API status after a successful health fetch', async () => {
    mockFetchOk({ status: 'healthy' });
    render(<HealthStatus />);
    await waitFor(() =>
      expect(screen.getByRole('status')).toHaveTextContent('healthy'),
    );
  });

  it('shows unavailable when the health fetch fails', async () => {
    mockFetchFail();
    render(<HealthStatus />);
    await waitFor(() =>
      expect(screen.getByRole('status')).toHaveTextContent('unavailable'),
    );
  });

  it('shows unavailable when the server returns a non-OK status', async () => {
    vi.stubGlobal(
      'fetch',
      vi.fn().mockResolvedValue({
        ok: false,
        status: 503,
        json: () => Promise.resolve({}),
      } as unknown as Response),
    );
    render(<HealthStatus />);
    await waitFor(() =>
      expect(screen.getByRole('status')).toHaveTextContent('unavailable'),
    );
  });
});
