### File: `Dockerfile` (CREATE)

```dockerfile
# ── Stage 1: Build ──────────────────────────────────────────────────────────
FROM node:20-alpine AS builder

WORKDIR /app

# VITE_* build-time vars must be ARG→ENV before `npm run build` so Vite
# can inline them into the bundle at build time.
ARG VITE_MSAL_CLIENT_ID
ARG VITE_MSAL_API_CLIENT_ID

ENV VITE_MSAL_CLIENT_ID=${VITE_MSAL_CLIENT_ID}
ENV VITE_MSAL_API_CLIENT_ID=${VITE_MSAL_API_CLIENT_ID}

# Install dependencies first (layer-cached when package files are unchanged)
COPY package*.json ./
RUN npm ci --ignore-scripts

COPY . .
RUN npm run build

# ── Stage 2: Serve ───────────────────────────────────────────────────────────
# nginx master briefly holds root to bind :80; worker processes run as the
# unprivileged `nginx` user — satisfying the non-root serving requirement.
FROM nginx:1.27-alpine AS runtime

# Remove default config and replace with SPA-aware config
RUN rm /etc/nginx/conf.d/default.conf
COPY nginx.conf /etc/nginx/conf.d/default.conf

# Copy built assets from the builder stage
COPY --from=builder /app/dist /usr/share/nginx/html

# Ensure the nginx user owns all served content
RUN chown -R nginx:nginx /usr/share/nginx/html

EXPOSE 80

CMD ["nginx", "-g", "daemon off;"]
```

